#!/usr/bin/env bash
# ──────────────────────────────────────────────────────────────
# cleanup.sh — Kill all processes and clean temporary files
#              generated by the Phage Therapy Prediction System.
#
# Usage:
#   ./cleanup.sh          Kill processes + remove temp files
#   ./cleanup.sh --full   Also remove uploaded files and logs
# ──────────────────────────────────────────────────────────────
set -euo pipefail

PROJECT_ROOT="$(cd "$(dirname "$0")" && pwd)"
BACKEND_PORT=8000
FRONTEND_PORT=3000
BACKEND_PID_FILE="$PROJECT_ROOT/.backend.pid"
FRONTEND_PID_FILE="$PROJECT_ROOT/.frontend.pid"

echo "═══════════════════════════════════════════════════════"
echo "  Phage Therapy — Cleanup"
echo "═══════════════════════════════════════════════════════"
echo ""

# ──── 1. Kill server processes ──────────────────────────────
echo "▸ Stopping servers…"
stopped=0

for pidfile in "$BACKEND_PID_FILE" "$FRONTEND_PID_FILE"; do
    if [ -f "$pidfile" ]; then
        pid=$(cat "$pidfile")
        if kill -0 "$pid" 2>/dev/null; then
            kill "$pid" 2>/dev/null || true
            stopped=1
            echo "  Killed PID $pid (from $(basename "$pidfile"))"
        fi
        rm -f "$pidfile"
    fi
done

# Kill anything still on the ports
for port in "$BACKEND_PORT" "$FRONTEND_PORT"; do
    pids=$(lsof -ti:"$port" 2>/dev/null || true)
    if [ -n "$pids" ]; then
        echo "$pids" | xargs kill -9 2>/dev/null || true
        stopped=1
        echo "  Killed process(es) on port $port"
    fi
done

# Kill any lingering uvicorn or vite/node processes from this project
for pattern in "uvicorn backend.app:app" "vite.*frontend"; do
    pids=$(pgrep -f "$pattern" 2>/dev/null || true)
    if [ -n "$pids" ]; then
        echo "$pids" | xargs kill -9 2>/dev/null || true
        stopped=1
        echo "  Killed lingering process(es) matching '$pattern'"
    fi
done

if [ $stopped -eq 1 ]; then
    echo "  ✓ All processes stopped"
else
    echo "  No running processes found"
fi

# ──── 2. Remove temp / cache files ─────────────────────────
echo ""
echo "▸ Cleaning temporary files…"
cleaned=0

# PID files
for f in "$BACKEND_PID_FILE" "$FRONTEND_PID_FILE"; do
    if [ -f "$f" ]; then rm -f "$f"; cleaned=1; fi
done

# Python bytecode caches
count=$(find "$PROJECT_ROOT" -type d -name "__pycache__" 2>/dev/null | wc -l | tr -d ' ')
if [ "$count" -gt 0 ]; then
    find "$PROJECT_ROOT" -type d -name "__pycache__" -exec rm -rf {} + 2>/dev/null || true
    echo "  Removed $count __pycache__ directories"
    cleaned=1
fi

# .pyc files outside __pycache__
count=$(find "$PROJECT_ROOT" -name "*.pyc" -type f 2>/dev/null | wc -l | tr -d ' ')
if [ "$count" -gt 0 ]; then
    find "$PROJECT_ROOT" -name "*.pyc" -type f -delete 2>/dev/null || true
    echo "  Removed $count .pyc files"
    cleaned=1
fi

# Pytest / coverage caches
for d in .pytest_cache .coverage htmlcov; do
    if [ -e "$PROJECT_ROOT/$d" ]; then
        rm -rf "$PROJECT_ROOT/$d"
        echo "  Removed $d"
        cleaned=1
    fi
done

if [ $cleaned -eq 0 ]; then
    echo "  Nothing to clean"
else
    echo "  ✓ Temp files cleaned"
fi

# ──── 3. Full cleanup (optional) ───────────────────────────
if [ "${1:-}" = "--full" ]; then
    echo ""
    echo "▸ Full cleanup…"

    # Log files
    for f in .backend.log .frontend.log; do
        if [ -f "$PROJECT_ROOT/$f" ]; then
            rm -f "$PROJECT_ROOT/$f"
            echo "  Removed $f"
        fi
    done

    # Uploaded files
    if [ -d "$PROJECT_ROOT/uploads" ]; then
        count=$(find "$PROJECT_ROOT/uploads" -type f 2>/dev/null | wc -l | tr -d ' ')
        rm -rf "$PROJECT_ROOT/uploads"
        echo "  Removed uploads/ ($count files)"
    fi

    echo "  ✓ Full cleanup complete"
fi

# ──── Summary ──────────────────────────────────────────────
echo ""
echo "═══════════════════════════════════════════════════════"
echo "  Cleanup complete!"
echo ""
echo "  Tip: Run with --full to also remove logs and uploads"
echo "═══════════════════════════════════════════════════════"
